package com.recettealarm.app;import android.Manifest;import android.app.*;import android.content.*;import android.database.*;import android.os.*;import android.view.*;import android.widget.*;import java.io.*;
public class MainActivity extends Activity{DB db;LinearLayout list;public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},5);draw();}
 void draw(){LinearLayout r=UI.root(this);r.addView(UI.tv(this,"Bonjour Chef ! 👋",16,0));r.addView(UI.tv(this,"Recette Alarm",32,1));Button add=UI.btn(this,"+ Nouvelle Recette");r.addView(add);add.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class)));Button shop=UI.btn(this,"Liste de courses automatique");r.addView(shop);shop.setOnClickListener(v->share(db.shoppingList()));r.addView(UI.tv(this,"Vos Recettes",22,1));list=r;load();}
 void load(){Cursor c=db.recipes();while(c.moveToNext()){long id=c.getLong(c.getColumnIndexOrThrow("id"));String t=c.getString(c.getColumnIndexOrThrow("title"));String cat=c.getString(c.getColumnIndexOrThrow("category"));int time=c.getInt(c.getColumnIndexOrThrow("time"));int serv=c.getInt(c.getColumnIndexOrThrow("servings"));TextView card=UI.card(this,cat+" • "+time+" min • "+serv+" pers.\n"+t);list.addView(card);card.setOnClickListener(v->startActivity(new Intent(this,DetailActivity.class).putExtra("id",id)));}c.close();}
 void share(String s){Intent i=new Intent(Intent.ACTION_SEND);i.setType("text/plain");i.putExtra(Intent.EXTRA_TEXT,s);startActivity(Intent.createChooser(i,"Partager"));}
}
